const raw = $input.first().json;
const input = raw.body || raw;

const episodeId = input.episode_id;
const episodeTitle = input.episode_title;
const thumbnailType = input.thumbnail_type;
const customScene = input.custom_scene_description || '';
const pose = input.pose;

// Character consistency markers (MUST be in every prompt)
const consistencyMarkers = `American Red Nose Pitbull, adult male, strong muscular realistic build, rich reddish-brown copper coat, distinctive red/liver nose, amber/honey eyes, natural uncropped rose ears, small healed scar across left brow, wearing sleeveless black coveralls slightly unzipped over bare muscular chest, black military tactical boots. Controlled intelligence, gentleman strategist expression. NOT aggressive. NOT playful. Watchful. Calm. 2D cel-shaded style.`;

// Negative prompt (ALWAYS include)
const negativePrompt = `\n\nNegative prompt: Blue nose, black nose, gray coat, brindle, white coat, cropped ears, aggressive snarling, teeth showing, cute puppy, playful, tongue out, bright colors, butterfly bowtie, fabric bowtie, silk bowtie, bowtie at collar, exaggerated bodybuilder, beast mode, suburban setting, grass yard, dog park, stock photo, cheerful, multiple dogs, human face, neon, photorealistic, 3D render, watermark, text, logo`;

// Pose prompt mappings
const posePrompts = {
  P1: `Sitting upright in 3/4 angle, looking off-frame to the right. Composed, dignified, alert posture. Dark Steel (#1E1E20) background. Single Rust Orange (#9A4C22) sodium vapor light casting warm directional light from upper left. Roger Deakins-style single-source lighting. Heavy vignette with 30-50% edge darkening. Film grain at 20%. Urban industrial environment hints in deep shadow.`,
  P2: `Standing facing camera, shot from slightly below eye level. Powerful upright posture, arms relaxed at sides. Harsh overhead light creating dramatic shadows under brow and jaw. Dark Steel (#1E1E20) background with subtle concrete texture. Roger Deakins-style top lighting. Heavy vignette. Film grain at 20%. Authority and controlled strength.`,
  P3: `Lying beside contextual objects (worn leather journal, vintage radio, tactical gear), head resting up on one paw. Relaxed but watchful expression, eyes tracking something off-frame. Warm Earth Clay (#7E6551) toned ambient light. Dark Steel (#1E1E20) floor surface. Roger Deakins-style practical lighting from nearby lamp. Film grain at 20%. Subtle vignette.`,
  P4: `Sitting at the edge of an urban rooftop, back partially to camera, looking out over city lights far below. Night scene. Atmospheric fog and haze. Silhouette with Rust Orange (#9A4C22) rim light from city glow. Dark Steel (#1E1E20) sky. Roger Deakins-style backlight silhouette. Heavy vignette. Film grain at 20%. Philosophical, contemplative mood.`,
  P5: `Extreme close-up of face, one amber/honey eye fully visible as the focal anchor. Shallow depth of field f/1.4. Healed scar across left brow clearly visible. Dark Steel (#1E1E20) background thrown completely out of focus. Roger Deakins-style close portrait lighting, single soft source from camera left. Film grain at 20%. Subtle vignette. Intensity without aggression.`,
  P6: `Walking through an empty urban street mid-stride, moving toward camera at slight angle. Wet asphalt reflecting sparse streetlights. Fog rolling through the scene. Roger Deakins-style atmospheric depth with layered light sources receding into distance. Dark Steel (#1E1E20) dominant palette. Rust Orange (#9A4C22) from sodium vapor streetlights. Heavy vignette. Film grain at 20%. Solitary, purposeful, aftermath energy.`
};

// Thumbnail type to pose mapping
const typeToPose = {
  hook: 'P5',
  authority: 'P2',
  product: 'P3',
  philosophical: 'P4',
  dramatic: 'P1',
  aftermath: 'P6'
};

// Use provided pose or fall back to type mapping
const selectedPose = pose || typeToPose[thumbnailType];
const posePrompt = posePrompts[selectedPose] || posePrompts[typeToPose[thumbnailType]];

// Build the full prompt
let fullPrompt = `${consistencyMarkers}\n\n${posePrompt}`;

// Add episode context
fullPrompt += `\n\nEpisode context: "${episodeTitle}" (Episode ${episodeId}).`;

// Add custom scene description if provided
if (customScene) {
  fullPrompt += `\n\nAdditional scene direction: ${customScene}`;
}

// Add thumbnail composition directive
fullPrompt += `\n\nYouTube thumbnail composition, bold dramatic, 1280x720, high impact. Colors: Dark Steel (#1E1E20), Rust Orange (#9A4C22), Earth Clay (#7E6551), Bone White (#E7E7E1). Typography style: Anton condensed uppercase headlines. Film grain 20%, heavy vignette, Roger Deakins cinematic lighting.`;

// Append negative prompt
fullPrompt += negativePrompt;

const timestamp = Date.now();
const filename = `bowtie-thumb-${episodeId}-${thumbnailType}-${timestamp}.png`;

return {
  episodeId,
  episodeTitle,
  thumbnailType,
  pose: selectedPose,
  prompt: fullPrompt,
  filename,
  timestamp
};
